import React, { useState } from 'react';
import './BookingScreen.css';

const TIME_SLOTS = ['10:30', '11:00', '11:30', '12:00'];
const ADULT_FARE = 2500;

export default function BookingScreen({ departure, destination, onBack, onConfirm }) {
  const [selectedTime, setSelectedTime] = useState(null);
  const [adults, setAdults] = useState(1);
  const [children, setChildren] = useState(0);

  const total = ADULT_FARE * (adults + children);

  const handleConfirm = () => {
    if (!selectedTime) return;
    onConfirm({
      departure,
      destination,
      time: selectedTime,
      passengers: adults + children,
      adults,
      children,
      total,
    });
  };

  return (
    <div className="booking-screen">
      {/* 헤더 */}
      <div className="booking-header">
        <button className="back-btn" onClick={onBack}>‹</button>
        <h2 className="booking-title">DRT 예약</h2>
        <div style={{ width: 40 }} />
      </div>

      {/* 출발 / 목적지 폼 */}
      <div className="route-form-card">
        <div className="route-field-group">
          <p className="route-label">출발</p>
          <div className="route-input">
            <span className="route-input-text">{departure}</span>
          </div>
        </div>

        <div className="swap-row">
          <button className="swap-btn">↕</button>
        </div>

        <div className="route-field-group">
          <p className="route-label">목적지</p>
          <div className="route-input route-input-dest">
            <span className="route-input-text">{destination.name}</span>
          </div>
        </div>
      </div>

      {/* 탑승 시간 */}
      <div className="booking-card">
        <p className="booking-label">탑승 시간</p>
        <div className="time-row">
          {TIME_SLOTS.map((t) => (
            <button
              key={t}
              className={`time-chip ${selectedTime === t ? 'active' : ''}`}
              onClick={() => setSelectedTime(t)}
            >
              {t}
            </button>
          ))}
        </div>
        <p className="time-note">KTX 도착 후 약 10분 내 배차</p>
      </div>

      {/* 인원 선택 */}
      <div className="booking-card">
        <p className="booking-label">인원 선택</p>

        <div className="pax-row">
          <span className="pax-type">어른</span>
          <div className="pax-ctrl">
            <button
              className="pax-minus"
              onClick={() => setAdults((a) => Math.max(1, a - 1))}
              disabled={adults <= 1}
            >
              −
            </button>
            <span className="pax-count">{adults}</span>
            <button
              className="pax-plus"
              onClick={() => setAdults((a) => Math.min(8, a + 1))}
            >
              +
            </button>
          </div>
        </div>

        <div className="pax-row">
          <span className="pax-type">어린이</span>
          <div className="pax-ctrl">
            <button
              className="pax-minus"
              onClick={() => setChildren((c) => Math.max(0, c - 1))}
              disabled={children <= 0}
            >
              −
            </button>
            <span className="pax-count">{children}</span>
            <button
              className="pax-plus"
              onClick={() => setChildren((c) => Math.min(8, c + 1))}
            >
              +
            </button>
          </div>
        </div>
      </div>

      {/* 요금 안내 */}
      <div className="fare-info">
        요금 안내: <strong>1인 {ADULT_FARE.toLocaleString()}원</strong>
      </div>

      {/* 예약 확정 버튼 */}
      <div className="confirm-wrap">
        <button
          className={`confirm-btn ${!selectedTime ? 'disabled' : ''}`}
          onClick={handleConfirm}
          disabled={!selectedTime}
        >
          예약 확정하기
        </button>
      </div>
    </div>
  );
}
